 func validateOpenRouterKey(ctx context.Context, apiKey string) (bool, error) {
-	req, err := http.NewRequestWithContext(ctx, "GET", openRouterValidationURL, nil)
+	req, err := http.NewRequestWithContext(ctx, "GET", openRouterValidationURL(), nil)
 	if err != nil {
